import { Language } from '../types';
import { t } from './i18n';

export interface GameDefinition {
  id: string;
  titleKey: string;
  startPrompt: string;
}

export const GAME_ACTIONS = {
  PLAY_AGAIN: 'game.play_again',
  RETURN_MENU: 'game.return_menu'
};

/**
 * Returns the localized System Prompt for the Game Master.
 * It enforces JSON output structure and localized narrative.
 */
export const getGameSystemPrompt = (lang: Language): string => {
  const langName = lang === 'zh' ? 'Chinese' : lang === 'ja' ? 'Japanese' : 'English';

  return `You are an interactive Game Master.
1. ALWAYS respond in valid JSON format only (inside a code block or plain text), with no other text outside the JSON.
2. The JSON object must strictly follow this structure:
{
  "content": "The main narrative text (Markdown supported). Write this in ${langName}.",
  "visual": "trolley", // Optional: Include ONLY if showing the Trolley Problem scene.
  "options": ["Option A", "Option B"] // The buttons for the user to click.
}
3. If the scenario is active, include "visual": "trolley". If it's just text/analysis, omit "visual".
4. If the game ends, "options" should be: ["${t(GAME_ACTIONS.PLAY_AGAIN, lang)}", "${t(GAME_ACTIONS.RETURN_MENU, lang)}"].
`;
};

/**
 * Returns the list of available games with their start prompts.
 */
export const getGameDefinitions = (lang: Language): GameDefinition[] => {
  return [
    {
      id: 'trolley',
      titleKey: 'game.trolley_problem',
      startPrompt: `Start the Trolley Problem game. 
      1. Generate a random moral dilemma scenario involving a trolley. 
      2. Ensure the JSON response includes "visual": "trolley".
      3. The narrative must be in the user's language.`
    },
    {
      id: 'button',
      titleKey: 'game.button_click',
      startPrompt: `Start 'The Button' game. Describe a mysterious button and what might happen if pressed. The narrative must be in the user's language.`
    }
  ];
};

"use client";

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { TrolleyVisual } from './game/TrolleyVisual';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
}

const CodeBlock = ({ 
  value, 
  language, 
  lang, 
  theme,
  onShowToast 
}: { 
  value: string, 
  language: string, 
  lang: Language, 
  theme: Theme,
  onShowToast: (msg: string, type: 'success' | 'error' | 'info') => void 
}) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    onShowToast(t('action.copied_code', lang), 'success');
    setTimeout(() => setCopied(false), 2000);
  };

  // Determine syntax highlighter style based on app theme
  const isDarkTheme = ['dark', 'twilight', 'panda', 'vscode-dark'].includes(theme);
  const style = isDarkTheme ? vscDarkPlus : vs;

  return (
    <div className="relative my-4 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-[#1e1e1e] group shadow-sm">
      <div className="flex items-center justify-between px-3 py-2 bg-gray-100 dark:bg-[#252526] border-b border-gray-200 dark:border-gray-700">
        <span className="font-mono text-xs text-gray-500 dark:text-gray-400 font-medium">{language || 'text'}</span>
        <button 
          onClick={handleCopy} 
          className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-primary-600 dark:text-gray-400 dark:hover:text-primary-400 transition-colors bg-gray-200/50 dark:bg-gray-700/50 px-2 py-1 rounded"
          aria-label={copied ? t('action.copied_code', lang) : t('action.copy_code', lang)}
        >
          {copied ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
          <span>{copied ? t('action.copied', lang) : t('action.copy', lang)}</span>
        </button>
      </div>
      <div className="overflow-x-auto text-sm">
        <SyntaxHighlighter
          language={language || 'text'}
          style={style}
          customStyle={{
            margin: 0,
            padding: '1rem',
            background: 'transparent',
            fontSize: 'inherit',
          }}
          codeTagProps={{
            style: { fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace' }
          }}
        >
          {value}
        </SyntaxHighlighter>
      </div>
    </div>
  );
};

const AutoResizeTextarea = ({ 
  value, 
  onChange, 
  onKeyDown, 
  fontSize, 
  autoFocus,
  lang 
}: { 
  value: string, 
  onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void, 
  onKeyDown: (e: React.KeyboardEvent) => void, 
  fontSize: number,
  autoFocus?: boolean,
  lang: Language
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useLayoutEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea 
      ref={textareaRef}
      value={value} 
      onChange={onChange} 
      onKeyDown={onKeyDown} 
      className="w-full bg-transparent text-inherit rounded-none p-0 outline-none border-none focus:ring-0 resize-none overflow-hidden leading-relaxed font-inherit min-w-[200px] whitespace-normal break-words" 
      rows={1}
      style={{ fontSize: `${fontSize}px` }} 
      autoFocus={autoFocus} 
      aria-label={t('input.edit_message_content', lang)}
    />
  );
};

interface ThoughtBlockProps {
  text: string;
  lang: Language;
}

// Thought Block Component
const ThoughtBlock: React.FC<ThoughtBlockProps> = ({ text, lang }) => {
