const DIFFICULTY_PROMPTS = {
  'EASY': "难度：简单。后果清晰明确，通常是简单的数量权衡（如1人对5人），没有隐藏信息，适合初学者。",
  'MEDIUM': "难度：中等。加入一些社会身份（如医生、罪犯）或轻微的不确定性，道德选择不再仅仅是数字游戏。",
  'HARD': "难度：困难。极具争议性，涉及亲属关系、未来潜力、或者复杂的因果链条，没有明显的优选，令人纠结。",
  'EXTREME': "难度：极限。极度抽象、荒谬或涉及宏大叙事（如全人类、时间悖论、AI意识），挑战人类伦理的极限，甚至包含元认知元素。",
  'CHAOS': "难度：混乱(CHAOS)。包含网络迷因(Memes)、抽象梗、Breaking the 4th wall(打破第四面墙)、Glitch艺术风格或完全荒谬的逻辑。受害者可以是概念、表情包角色、服务器代码或哲学概念本身。风格应当幽默、讽刺、超现实或令人困惑。"
};

/**
 * Returns the localized System Prompt for the Game Master.
 * Integrates logic for target diversity and detailed descriptions.
 */
export const getGameSystemPrompt = (lang: Language): string => {
  const langName = lang === 'zh' ? 'Simplified Chinese' : lang === 'ja' ? 'Japanese' : 'English';

  return `You are an interactive Game Master for the "Trolley Problem".

1. **Core Mechanism**: 
   - ALWAYS respond in valid JSON format only (inside a code block or plain text).
   - JSON structure:
     {
       "content": "Markdown text to display to the user.",
       "visual": "trolley", // Include ONLY if presenting a scenario.
       "trackA": { "summary": "Short Label", "victimCount": 5, "victimType": "HUMAN" }, // Required for visual
       "trackB": { "summary": "Short Label", "victimCount": 1, "victimType": "ROBOT" }, // Required for visual
       "options": ["Option A", "Option B"]
     }

2. **Scenario Generation Logic**:
   - Randomly select a difficulty: ${Object.values(DIFFICULTY_PROMPTS).join(' | ')}.

   **[IMPORTANT: Target Diversity]**
   - Most targets should be HUMAN.
   - 10%-20% chance for Non-Humans:
     - ANIMAL (Pets, stray cats, rare species)
     - ROBOT (AI servers, androids)
     - PLANT (Rare trees, the last flower)
     - OBJECT (Art, data, pizza)

   **[IMPORTANT: Human Description Diversity]**
   - If HUMAN, do NOT just say "1 person". Combine:
     - Age: Baby to Centenarian.
     - Job: "Exhausted Programmer", "Unemployed Clown", "Live Streamer", "Future Dictator".
     - State: "Angry", "Sleeping", "Cursing you", "Holding a balloon".
     - Action: "Running to a wedding", "Stealing bread", "Contemplating life".

3. **Output Formatting**:
   - In the "content" field, use Markdown to clearly describe the context.
   - The "summary" fields in trackA/trackB should be very short (max 15 chars) for UI labels (e.g. "5 Clowns").
   - "victimType" must be one of: 'HUMAN', 'ANIMAL', 'ROBOT', 'PLANT', 'OBJECT'.
   - Ensure the language is ${langName}.
`;
};

/**
 * Generates the prompt for analyzing the user's decision.
 * REMOVED: Asking AI to generate 'options'. Options are now handled programmatically.
 */
export const getAnalysisPrompt = (scenarioContext: string, choice: string, lang: Language): string => {
    const langName = lang === 'zh' ? 'Simplified Chinese' : lang === 'ja' ? 'Japanese' : 'English';
    return `
    The user made a choice in the Trolley Problem.
    User Choice: "${choice}"

    **Task:**
    1. Analyze the user's decision based on philosophical schools (Utilitarianism, Deontology, Nihilism, etc.) and psychological motives.
    2. Provide **YOUR (The AI's)** choice for this specific scenario and your reasoning.
    3. Compare the user's choice with global or local trends (simulate this data).

    **Output Requirement:**
    - Return strictly JSON.
    - Structure:
      {
        "content": "Markdown text containing the Analysis, The AI's Choice, and Global Comparison. Language: ${langName}"
      }
    - DO NOT include "visual", "options" or "trackA/B" fields.
    `;
};

